diagram.mermaid:
classDiagram
  class Sensory { +raw_input_per_tick }
  class Working { +top_N_items }
  class ShortTerm { +recent_verbatim_1_7d }
  class Episodic { +compressed_summaries_5_10x }
  class LongTerm { +distilled_rules }
  Sensory --> Working : promote
  Working --> ShortTerm : promote
  ShortTerm --> Episodic : compact
  Episodic --> LongTerm : distill
  LongTerm ..> Working : rehearsal lifts back

classDiagram
  class Entity { +id +type +attrs }
  class Relation { +subject +predicate +object }
  class GraphStore { +neo4j_or_rdf_or_json }
  class VectorIndex { +entry_points }
  Entity --> Relation : participates_in
  Relation --> GraphStore : persisted_in
  VectorIndex ..> Entity : finds entry points
  GraphStore ..> Relation : Cypher / SPARQL traversal

classDiagram
  class MainContext {
    +system_prompt
    +working_set
    +recent_messages
  }
  class Recall { +raw_history }
  class Archival { +vector_store }
  class Model {
    +read_recall()
    +write_archival()
    +search_archival()
  }
  Model --> MainContext : RAM
  Model --> Recall : disk read
  Model --> Archival : disk read/write
